module multi_pipe_8bit #(
    parameter size = 8
) (
    input clk,
    input rst_n,
    input [size-1:0] mul_a,
    input [size-1:0] mul_b,
    input mul_en_in,
    output reg mul_en_out,
    output reg [size*2-1:0] mul_out
);

localparam IDLE = 3'b000;
localparam LOAD = 3'b001;
localparam CALC = 3'b010;
localparam OUT  = 3'b011;

reg [2:0] state, next_state;
reg [15:0] mul_out_reg;
reg [15:0] temp [0:7];
reg [15:0] sum [0:7];
reg [7:0] mul_a_reg, mul_b_reg;
reg [2:0] mul_en_out_reg;

always @(posedge clk or negedge rst_n) begin
    if (!rst_n) begin
        state <= IDLE;
        mul_en_out_reg <= 3'b0;
        mul_out_reg <= 16'b0;
    end else begin
        state <= next_state;
        mul_en_out_reg <= {mul_en_out_reg[1:0], mul_en_in};
    end
end

always @* begin
    case(state)
        IDLE: begin
            if(mul_en_in) begin
                next_state = LOAD;
            end else begin
                next_state = IDLE;
            end
        end

        LOAD: begin
            if(!mul_en_in) begin
                next_state = CALC;
            end else begin
                next_state = LOAD;
            end
        end

        CALC: begin
            if(mul_en_out_reg[2]) begin
                next_state = OUT;
            end else begin
                next_state = CALC;
            end
        end

        OUT: begin
            if(!mul_en_out_reg[2]) begin
                next_state = IDLE;
            end else begin
                next_state = OUT;
            end
        end

        default: next_state = IDLE;
    endcase
end

always @(posedge clk) begin
    if (mul_en_in) begin
        mul_a_reg <= mul_a;
        mul_b_reg <= mul_b;
    end else begin
        mul_a_reg <= 8'b0;
        mul_b_reg <= 8'b0;
    end
end

genvar i;
generate
    for(i = 0; i < 8; i=i+1) begin
        assign temp[i] = {{8{mul_b_reg[i]}}, mul_a_reg} << i;
    end
endgenerate

always @(posedge clk) begin
    sum[0] <= temp[0];
    sum[1] <= temp[1] + temp[2];
    sum[2] <= temp[3] + temp[4];
    sum[3] <= temp[5] + temp[6];
    sum[4] <= temp[7];
    sum[5] <= sum[1] + sum[2];
    sum[6] <= sum[3] + sum[4];
    sum[7] <= sum[5] + sum[6];
end

always @(posedge clk) begin
    if (mul_en_out_reg[2]) begin
        mul_out_reg <= sum[0] + sum[7];
    end else begin
        mul_out_reg <= 16'b0;
    end
end

assign mul_out = mul_out_reg;

endmodule
